import type ColorStop from "../../../renderers/visualVariables/support/ColorStop.js";
import type SmartMappingPrimaryHandleSliderViewModel from "../SmartMappingPrimaryHandleSliderViewModel.js";
import type { GradientStopInfo } from "../types.js";
import type { SmartMappingPrimaryHandleSliderViewModelProperties } from "../SmartMappingPrimaryHandleSliderViewModel.js";

export interface ColorSliderViewModelProperties extends SmartMappingPrimaryHandleSliderViewModelProperties, Partial<Pick<ColorSliderViewModel, "stops">> {}

/**
 * Provides the logic for the [ColorSlider](https://developers.arcgis.com/javascript/latest/references/core/widgets/smartMapping/ColorSlider/) widget.
 *
 * @since 4.12
 * @see [ColorSlider](https://developers.arcgis.com/javascript/latest/references/core/widgets/smartMapping/ColorSlider/)
 */
export default class ColorSliderViewModel extends SmartMappingPrimaryHandleSliderViewModel<ColorStop> {
  constructor(properties?: ColorSliderViewModelProperties);
  /**
   * The color stops from the [ColorVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/ColorVariable/)
   * to link to the slider. The colors in these stops will be used
   * to render the color gradient on the slider's track. They should match the colors
   * rendered in the associated layer's renderer.
   *
   * @example
   * colorRendererCreator.createContinuousRenderer({
   *   layer: featureLayer,
   *   field: "fieldName",
   *   basemap: "gray-vector"
   * }).then(function(colorResponse){
   *   const slider = new ColorSlider({
   *     viewModel: new ColorSliderVM({
   *       stops: colorResponse.visualVariable.stops,
   *       min: colorResponse.statistics.min,
   *       max: colorResponse.statistics.max,
   *     }),
   *     container: "sliderDiv"
   *   });
   * });
   */
  accessor stops: ColorStop[];
  /** Generates the color ramp gradient rendered on the slider track. */
  getStopInfo(): GradientStopInfo[];
}